using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddChatClient(chatBuilder =>
    chatBuilder.UseOpenAIChatClient(
        builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18"));

builder.Services.AddSingleton<NoteService>();
builder.Services.AddSingleton<WebSearchService>();
builder.Services.AddSingleton<ResearchAgentService>();

builder.Logging.SetMinimumLevel(LogLevel.Warning);

var host = builder.Build();

var agentService = host.Services.GetRequiredService<ResearchAgentService>();

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));
Console.WriteLine();

await agentService.ResearchTopicAsync(topic);

