namespace ResearchAgent;

/// <summary>
/// In-memory note storage for the research agent.
/// </summary>
public sealed class NoteService
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    public void AddNote(string title, string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
    }

    public string GetAllNotesFormatted()
    {
        if (_notes.Count == 0)
        {
            return "No notes recorded yet.";
        }

        return string.Join(Environment.NewLine + Environment.NewLine,
            _notes.Select((n, i) => $"[{i + 1}] {n.Title}\n{n.Content}"));
    }
}

public sealed record Note(string Title, string Content, DateTime CreatedAt);

namespace ResearchAgent;

/// <summary>
/// Simulated web search service. Replace with a real search API (e.g., Bing Search) for production use.
/// </summary>
public sealed class WebSearchService
{
    private static readonly Dictionary<string, string[]> SimulatedResults = new(StringComparer.OrdinalIgnoreCase)
    {
        ["artificial intelligence"] =
        [
            "AI is a branch of computer science focused on building systems capable of performing tasks that typically require human intelligence, such as visual perception, speech recognition, and decision-making.",
            "Modern AI is largely driven by machine learning and deep learning techniques. Large language models (LLMs) like GPT-4 and Claude have demonstrated remarkable capabilities in understanding and generating human language.",
            "Key concerns around AI include alignment (ensuring AI acts in accordance with human values), job displacement, privacy, and the concentration of power among a few large technology companies.",
        ],
        ["climate change"] =
        [
            "Global average temperatures have risen approximately 1.1°C above pre-industrial levels. The Paris Agreement aims to limit warming to 1.5°C.",
            "Major contributors to climate change include fossil fuel combustion, deforestation, and industrial agriculture. The energy sector accounts for about 73% of global greenhouse gas emissions.",
            "Solutions being pursued include renewable energy adoption, carbon capture technologies, reforestation, and policy measures such as carbon pricing and emissions trading systems.",
        ],
        ["quantum computing"] =
        [
            "Quantum computers use qubits that can exist in superposition, enabling them to process certain computations exponentially faster than classical computers.",
            "Current quantum computers are in the NISQ (Noisy Intermediate-Scale Quantum) era, with devices like IBM's 1000+ qubit processors and Google's Sycamore demonstrating quantum advantage for specific tasks.",
            "Practical applications include cryptography, drug discovery, materials science, optimization problems, and machine learning acceleration.",
        ],
    };

    public Task<SearchResult[]> SearchAsync(string query)
    {
        // Find best matching simulated results
        var results = SimulatedResults
            .Where(kvp => query.Contains(kvp.Key, StringComparison.OrdinalIgnoreCase)
                          || kvp.Key.Contains(query, StringComparison.OrdinalIgnoreCase))
            .SelectMany(kvp => kvp.Value)
            .Select((text, i) => new SearchResult($"Result {i + 1}", text, $"https://example.com/search?q={Uri.EscapeDataString(query)}&r={i + 1}"))
            .ToArray();

        if (results.Length == 0)
        {
            // Generic fallback for topics not in the simulated database
            results =
            [
                new SearchResult(
                    $"Overview of {query}",
                    $"{query} is a topic of significant interest in current research and public discourse. Multiple sources provide varying perspectives on its implications and developments.",
                    $"https://example.com/search?q={Uri.EscapeDataString(query)}&r=1"),
                new SearchResult(
                    $"Recent developments in {query}",
                    $"Recent advances in {query} have attracted attention from researchers, policymakers, and industry professionals. The field continues to evolve rapidly with new findings published regularly.",
                    $"https://example.com/search?q={Uri.EscapeDataString(query)}&r=2"),
            ];
        }

        return Task.FromResult(results);
    }
}

public sealed record SearchResult(string Title, string Snippet, string Url);

using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Orchestrates the research agent using Microsoft Agent Framework.
/// </summary>
public sealed class ResearchAgentService
{
    private readonly IChatClient _chatClient;
    private readonly NoteService _noteService;
    private readonly WebSearchService _webSearchService;

    public ResearchAgentService(
        IChatClient chatClient,
        NoteService noteService,
        WebSearchService webSearchService)
    {
        _chatClient = chatClient;
        _noteService = noteService;
        _webSearchService = webSearchService;
    }

    public async Task ResearchTopicAsync(string topic, CancellationToken cancellationToken = default)
    {
        var tools = CreateTools();

        var agent = new ChatClientAgent(
            _chatClient,
            instructions: """
                You are a research agent. Your goal is to thoroughly research the given topic using the available tools.

                Follow this workflow:
                1. Use the web_search tool to search for information about the topic.
                2. Use the save_note tool to record key findings with descriptive titles.
                3. Search for additional aspects of the topic (different angles, recent developments, implications).
                4. Save notes for each important finding.
                5. Once you have gathered enough information (at least 2-3 searches), use get_all_notes to review your findings.
                6. Provide a comprehensive summary based on your research notes.

                Be thorough but concise. Focus on factual information and cite your sources where possible.
                """,
            name: "ResearchAgent",
            description: "An agent that researches topics by searching the web and taking notes.",
            tools: tools);

        var runOptions = new ChatClientAgentRunOptions(new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
        });

        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session: null,
            options: runOptions,
            cancellationToken: cancellationToken);

        Console.WriteLine("═══ Research Summary ═══");
        Console.WriteLine();
        Console.WriteLine(response.Text);
        Console.WriteLine();
        Console.WriteLine("═══ Notes Collected ═══");
        Console.WriteLine();
        Console.WriteLine(_noteService.GetAllNotesFormatted());
    }

    private List<AITool> CreateTools()
    {
        return
        [
            AIFunctionFactory.Create(SearchWebAsync, new AIFunctionFactoryOptions
            {
                Name = "web_search",
                Description = "Search the web for information about a topic. Returns relevant search results with titles, snippets, and URLs.",
            }),
            AIFunctionFactory.Create(SaveNoteAsync, new AIFunctionFactoryOptions
            {
                Name = "save_note",
                Description = "Save a research note with a title and content. Use this to record key findings during research.",
            }),
            AIFunctionFactory.Create(GetAllNotes, new AIFunctionFactoryOptions
            {
                Name = "get_all_notes",
                Description = "Retrieve all saved research notes. Use this to review findings before writing a summary.",
            }),
        ];
    }

    [Description("Search the web for information about a query.")]
    private async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        var results = await _webSearchService.SearchAsync(query);

        var formatted = results.Select(r => $"Title: {r.Title}\nSnippet: {r.Snippet}\nURL: {r.Url}");
        return string.Join("\n---\n", formatted);
    }

    [Description("Save a research note.")]
    private Task<string> SaveNoteAsync(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content of the note")] string content)
    {
        Console.WriteLine($"  📝 Saving note: \"{title}\"");

        _noteService.AddNote(title, content);
        return Task.FromResult($"Note saved: \"{title}\"");
    }

    [Description("Get all saved research notes.")]
    private string GetAllNotes()
    {
        Console.WriteLine("  📋 Retrieving all notes...");
        return _noteService.GetAllNotesFormatted();
    }
}

