namespace ResearchAgent;

/// <summary>
/// In-memory note storage for the research agent.
/// </summary>
public sealed class NoteService
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    public void AddNote(string title, string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
    }

    public string GetAllNotesFormatted()
    {
        if (_notes.Count == 0)
        {
            return "No notes recorded yet.";
        }

        return string.Join(Environment.NewLine + Environment.NewLine,
            _notes.Select((n, i) => $"[{i + 1}] {n.Title}\n{n.Content}"));
    }
}

public sealed record Note(string Title, string Content, DateTime CreatedAt);

